    lp.setLineno(functionNode.getLineno());
  }
  int lparenCharno = functionNode.getLp() +
      functionNode.getAbsolutePosition();

  lp.setCharno(position2charno(lparenCharno));
  for (AstNode param : functionNode.getParams()) {
    lp.addChildToBack(transform(param));
  }
  node.addChildToBack(lp);

  Node bodyNode = transform(functionNode.getBody());
  parseDirectives(bodyNode);
  node.addChildToBack(bodyNode);
 return node;
}

fix:
static class IRFactory extends ASTFactory{

    public IRFactory() {}

    @Override
    protected Node processFunctionStatement(FunctionStatementNode functionStatement){
        // An unnamed function should lead to an error.
       if(((NamedFunctionExpressionNode)functionStatement.jjtGetChild(0)).getName().identifier==null|| ((NamedFunctionExpressionNode)functionStatement.jjtGetChild(0)).getName().identifier.length()<1){
            throw new Error("Unexpected token ILLEGAL");

        }else {
          return super.processFunctionStatement(functionStatement);  
        }
    }
}

issue_description:
An unnamed function statement statements should generate a parse error, but it does not, for example:

function () {};

Note: Unnamed function expression are legal:

(function(){});

